10→export function findClosestColorId(
11→	color: IStyleColorBase | null,
12→	palette: IProductColor[],
13→): number {
14→	if (!color || !palette.some((item) => item.rbgs?.length)) {
15→		logger.warn(
16→			'[findClosestColorId]: No color or palette provided, defaulting to color ID 0',
17→		);
18→		return 0;
19→	}
20→
21→	const referenceColor = palette.find((item) => item.name === color.color_name);
22→
23→	if (referenceColor) {
24→		logger.log(
25→			`[findClosestColorId]: Exact color match found for "${color.color_name}", using color ID ${referenceColor.id}`,
26→		);
27→		return referenceColor.id;
28→	}
29→	const selectedColorRGB = color.color_rgb;
30→
31→	if (!selectedColorRGB || !palette.length) {
32→		logger.warn(
33→			'[findClosestColorId]: No selected color RGB or empty palette, defaulting to color ID 0',
34→		);
35→		return 0;
36→	}
37→
38→	const colorsHash = getColorRGBToIdHash(palette);
39→
40→	const paletteColors = palette.reduce<RGBColor[]>((acc, color) => {
41→		if (color.rbgs?.[0]) {
42→			acc.push(color.rbgs[0]);
43→		}
44→		return acc;
45→	}, []);
46→
47→	const closestColor = closest(convertStringToRGB(selectedColorRGB), paletteColors);
48→
49→	const closestColorId = colorsHash[convertRGBToString(closestColor)] ?? 0;
50→
51→	logger.log(
52→		`[findClosestColorId]: Closest color to "${color.color_name}" (RGB: ${selectedColorRGB}) is color ID ${closestColorId}. colorsHash: ${JSON.stringify(colorsHash)}, paletteColors: ${JSON.stringify(paletteColors)}, closestColor: ${JSON.stringify(closestColor)}`,
53→	);
54→
55→	return closestColorId;
56→}
57→
58→function getColorRGBToIdHash(colors: IProductColor[]): Record<string, number> {
59→	return colors.reduce<Record<string, number>>((acc, color) => {
60→		if (color.rbgs?.[0]) {
61→			acc[convertRGBToString(color.rbgs[0])] = color.id;
62→		}
63→		return acc;
64→	}, {});
65→}
66→
67→export function convertRGBToString(rgb: RGBColor): string {
68→	return `R:${rgb.R},G:${rgb.G},B:${rgb.B}`;
69→}
70→
71→export function convertStringToRGB(str: string): RGBColor {
72→	const [R, G, B] = str.split(',');
73→	return {
74→		R: Number(R?.split(':')[1]),
75→		G: Number(G?.split(':')[1]),
76→		B: Number(B?.split(':')[1]),
77→	};
78→}
